import json
import pickle

# Custom class to show how the json and pickle handle it
class CustomObject:
    def __init__(self, name, data):
        self.name = name
        self.data = data

def save_preferences(prefs, filename, custom=False):
    with open(filename, 'w' if not custom else 'wb') as f:
        if not custom:
            f.write(json.dumps(prefs, default=lambda o: o.__dict__))
        else:
            pickle.dump(prefs, f)

def load_preferences(filename, custom=False):
    with open(filename, 'r' if not custom else 'rb') as f:
        if not custom:
            return json.load(f)
        else:
            return pickle.load(f)